def bead_sort(seq):
    for _ in range(len(seq)):
        for i in range(len(seq) - 1):
            if seq[i] > seq[i+1]:
                diff = seq[i] - seq[i+1]
                seq[i] -= diff
                seq[i+1] += diff
    return seq

if __name__ == "__main__":
    print(f"Sorted [3, 1]: {bead_sort([3, 1])}")
